(38,'Ryann','0ffd8e983b074960a2b2b88d49682fc7.webp','泰山的日出，美的如同一声叹息','<div>&nbsp; 时光荏苒，岁月匆匆，不知不觉间又到了冬天。还记得前年的冬天，也是这个时候，我和同事一行三人，来了一场说走就走的旅行，目标直指“五岳之尊”——泰山。</div><div>&nbsp; “岱宗夫如何，齐鲁青未了”，为了迎接日出，更为了挑战自己，我们选择了晚上攀爬。十二月份的泰山，晚上的温度可想而知，我们从十一点多开始从红门出发，一开始还爬的很快，也没有觉得很冷，反而还有点出汗，但随着海拔的增高和时间的推移，我们的速度越来越慢，山上的风也越来越冷，攀爬着的时候还好，一停下来就感觉冷风刺骨如坠冰窖，但箭在弦上不得不发，我们只能选择继续前进。</div><div><br></div><div>&nbsp; 经过中天门以后，山路越来越陡峭，我们都觉得越来越难走，心想，传说中的十八盘也不过如此了吧！没想到真正来到十八盘以后才发现，和前面一比，简直就是大巫见小巫啊！十八盘都不能用陡峭来形容，简直就是天梯啊！攀爬十八盘的过程就像坐过山车，没有最惊险，只有更惊险！</div><div>&nbsp; 因为是在晚上，我们看不到上面的路，还自我安慰自我鼓励地说：“可能快到了！可能快到了！”但台阶就像是在你脚下刚刚长出来的，你走一步，它就长一节，让你感觉永远走不完！但正如汪国真的诗：“没有比人更高的山，没有比脚更长的路！”只要敢于攀登，就永远路在脚下！</div><div><br></div><div>&nbsp; 终于，我们走过了十八盘，来到了南天门，离泰山之巅越来越近，而此时的温度也已经降到了零下十七八度，随身携带的矿泉水都已经冻成了冰，尽管我们把能穿的衣服都已经穿上,但还是冻的瑟瑟发抖，而此时距离日出还有一个多小时，经过五六个小时的攀爬，我们的体力也早已消耗殆尽。</div><div>没办法！我们只好找了个地方，每人租了件军大衣取暖，顺便补充下体力，等待日出的来临。山上的景色颇为壮丽，还有历朝历代的碑刻题字，让我有种穿越时空与时空交会的错觉，想到上至秦皇汉武文人骚客，下至贩夫走卒平民百姓，都曾在此驻足，顿感历史沧桑，而泰山千年如一日，没有厚此更没有薄彼，也许这正是他的伟大之处。</div><div><br></div><div>&nbsp; 就在这样的胡思乱想中，太阳从海平面一点点的升起，只见它越升越高越升越亮，周围都是红红的云霞，仿若新娘的嫁衣。而它破空而出的那一刻，光芒万丈普照大地，天地都好似穿上了盛装，我的心也跟着明亮起来。只是稍稍遗憾的是，因为温度太低，我们的手机要么被冻的没电，要么被冻的关机，没能拍几张像样的照片，但能亲眼目睹一次泰山的日出，此行已是无憾了。</div><div>&nbsp; 泰山的日出，美的如同一声叹息！当太阳终于升起来，我站在一块巨大的石头上，面前是蓬勃而出的旭日，脚下是屹立千年的泰山，身后是云蒸霞蔚的群峰，远眺是光芒万丈的尘世。那一刻，想想自己那点微不足道的前尘旧恨，再看看这座承载着中华五千年历史的巍巍泰山，“俯观五岳间，从生忽如寄！”</div><div><br></div><div></div><div>&nbsp; “会当凌绝顶，一览众山小”。只有站在山上才更能体会出这句诗的意境，而其实我们为了给以后再次攀爬留下空间，并没有登上最高的玉皇顶，我相信“无限风光在险峰”，也相信我们的人生就像登山，也一定会越来越高，也许我们也会遇到人生的十八盘，但只要咬咬牙挺过去，就一定会迎来灿烂的日出。等到“山登绝顶我为峰”的那一刻，我相信！我们一定会感谢，那个当初勇于攀登的自己。</div><div>&nbsp; 泰山，山如其名，自古以来就被寓意国泰民安，千百年来，文圣孔子“登东山而小鲁，登泰山而小天下”，太史公司马迁“人固有一死，或重于泰山，或轻于鸿毛”，李白“天门一长啸，万里清风来”，杜甫“会当凌绝顶，一览众山小”，苏轼、苏辙兄弟因未能登临泰山而抱憾“恨君不上东封顶，夜看金轮出九幽”，自诩“诗人爱山爱彻骨”的元好问。</div><div><br></div><div>&nbsp; 登泰山时“山灵见光怪，似喜诗人来”，就连自恋的曹植都宣称“我本泰山人”，可见，古往今来文人墨客对泰山都是无比的喜爱。下山时，我特意捡了几块好看的石头，想到这块石头也许就被李白摸过，那块石头也许就被孔子踩过，真是大大的满足了自己的那一点虚荣心。</div><div>&nbsp; 泰山是中华民族的精神象征，更是华夏历史与文化的缩影，不仅仅是文人墨客，秦皇汉武、光武玄宗都曾来泰山封禅，前后曾有十二个皇帝登临泰山，功臣将相更是不计其数。近现代伟人也都曾登临泰山。不管是古代还是现代，不管是得意还是失意，多少人都曾登临泰山驻足遥望！</div><div>&nbsp; 生活中人们也是动辄都爱说泰山，“责任重于泰山”，“安全重于泰山”，“恩情重于泰山”，总书记在多次讲话中都号召大家“人心齐，泰山移”，泰山，说他承载中华五千年的历史与文化一点都不为过！</div><div><br></div><div>&nbsp; 下山的时候我们也去碧霞元君祠烧了香磕了头，看看周围，有许许多多多和我们一样的人，或祈福或求子或烧香或还愿，看着他们虔诚无比的样子，我没有觉得他们封建迷信，只觉得感动非常。人在命运的面前何其渺小！“不如意事常八九，能与人言无二三”。</div><div>&nbsp; 当我们彷徨无助，当我们号啕大哭，当我们“上穷碧落下黄泉”般的寻求无果，当我们“衣带渐宽终不悔”似的求告无门，做为沧海一栗的我们，能祈求的大概也只有苍天和神灵了吧？人是该有一点信仰和寄托的，大到帝王的封禅，小到个人的祈福，说白了，不都是一种寄托吗？</div><div><br></div><div>&nbsp; 一路从泰山下来，或拍照留念，感受自然美景，或欣赏碑刻题字，体会人文剧变历史沧桑，古人说“读万卷书不如行万里路”，今人说“身体和灵魂必须有一个在路上”，对此深以为是！世界那么大，祖国这样美，但愿以后的自己，可以多有机会出来走走看看。</div>','2023-12-14'),
(39,'Ryann','2a4b16d17fc54753b0dd5b7dbeb5e13c.jpg','云龙山：自然与人文古迹融合','<p>&nbsp; 云龙山山分九节，蜿蜒起伏状似神龙，昂首向东北，曳尾于西南，故而得名。从黄茅冈到东坡石床，从云龙山上放鹤亭，到观景台下的青山绿水布衣人家……云龙山的华彩，经受了五千年的风野烟沙，形神兼具，是给予古城徐州的天然馈赠。<br></p><p><br></p><p>&nbsp; 登云龙山，除了美景相伴，浓厚的历史人文气息也将把你环绕。众多古迹散布各处，或与历史名人的行迹相关，或与徐州城市的发展相连。有从山顶绵延至山脚的兴化禅寺和清代陡峭险峻清净祥和的大士岩；还有北宋张山人故址，天上座、东坡石床、碑廊，关圣殿等人文古迹……云龙山脚下，云龙书院青墙黛瓦文蕴深厚。放鹤亭、招鹤亭、御碑亭……坐落在山间，栖身于亭内，身心便可安顿下来，听四面山色。在苍松翠柏的掩映下，曲径回廊，竹林花木，幽雅清静，别有洞天。每一步都能感受到历史的厚重。</p><p><br></p><p>&nbsp; 徐州音乐厅如紫薇花盛开在云龙湖畔。被四周山色、万顷碧波环绕的徐州水族展览馆。湖中路上遥望苏公塔，别有一番风味。湖南路云汇桥，充满着浓浓楚风汉韵……如果说“汉代三绝”是徐州悠久历史的沉淀，那云龙山的系列古迹则是徐州灿烂文化的精炼与升华。</p>','2023-12-14'),
(42,'Ryann','e7ca98788d1d4ef0b34793bd3d6af680.webp','论剑只应临西岳，华山归来无险峰','<p data-first-child=\'\'\'\' \'\'=\'\'\'\' data-pid=\'\'\'\' c5m5g0xw\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>爬山本来就是和自己独处的一个过程，放下生活中的一切杂念、烦恼、压力，只伴着自己的呼吸声，脚踏实地的走好每一步。虽然累但特别享受，因为你专注在这一刻，没有任何东西打扰你。所以这份爬山的累，只会让你感到踏实和沉静。</span><br></p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>徒步的过程也挺有意思的，一开始会先感到无比兴奋，上路后看到坑坑洼洼的地面会开始抱怨，等到要爬阶梯的时候，又瞬间崩溃。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' ftyy_40u\'\'=\'\'\'\'>伴着五味杂陈的心情，和登顶的决心，就这样累死累活的往上爬。直到登顶的那一刻，瞬间就又活过来了。就是这样一个生不如死又死后重生的心路历程，体验感真的太丰富有趣了！</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>都说华山以险著称，这个我早有耳闻。做攻略的时候，对千尺幢、鹞子翻身、长空栈道都有所关注。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' bl4yptw6\'\'=\'\'\'\'>只是恐高的我，能挑战的真的不多。所以当我徒步遇到千尺幢的时候，我还是一鼓作气决定挑战看看，爬了这个近乎90度坡度共1000层阶梯的险道。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>说真的我害怕极了，全程都不敢回头看，两只手紧紧拽着两旁的铁链，一步一脚印恨不得用踩出坑来的力气往上爬。虽然紧张到心快要跳出来了，但我还是调整好自己的呼吸，掌握好自己的节奏，同时默默还在给自己加油打气。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' ldkvwxf3\'\'=\'\'\'\'>爬到一半时神奇的事情发生了，我开始适应了这种恐惧，于是恐惧的念头就消失了，我也成功征服了千尺幢。爬完千尺幢，我整个人都湿透了，手脚一个劲儿的颤抖，紧张和害怕在这一刻才全都涌上来了。虽然心惊肉跳的的走了这么一遭，可我还是觉得很值得。因为我挑战过了，此行也就不留遗憾了。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>爬坡虽然慢了，可爬阶梯我还是很厉害的。一开始走我前面的小伙伴，全都在阶梯这关输给了我。因为他们在阶梯这里总是走走停停，而我全程则是一鼓作气爬上去的。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' przqo22c\'\'=\'\'\'\'>真的很累，生无可恋咬牙切齿的那种累，几度我都觉得自己的大腿根在往上抬的那一刻快要炸开了，尤其是遇到高的台阶。但也真的很爽，酣畅淋漓无与伦比的那种爽，因为你在征服你自己。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>不得不说，爬山最难的地方，是在你眼看着要登顶的时候，所剩不多的几节阶梯才真的是要人命呢。面对登顶的阶梯，我就算有一鼓作气的决心，也没有一鼓作气的实力。尤其是最后那几节，眼看着峰顶就在眼前，但就是爬的你心力交瘁痛苦不堪。会累到你连腰都直不起来，生生压低了身子才能继续往上爬，而且压得越低越轻松。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' yrt429_w\'\'=\'\'\'\'>&nbsp;这不就跟我们的人生一样吗？当成功就在你眼前的时候，反而是最触不可及时候。不来一场天人交战的决斗，你又怎么能真正触碰到成功。而且想要获得成功，也不是一件易事。你得能够俯下头颅，只有身段放的够低，腰板压得够弯，才能在最后关头一跃而上。和登顶一样，最后那几步，才是最磨人且最考验人的时候。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>累归累，折磨人归折磨人。但徒步真的让我很爽，身心爆爽的那种爽。原本我还想着徒步的时候，会和自己内心有一番精彩的对话。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' bwfi1xyi\'\'=\'\'\'\'>毕竟只有我自己，我一定能回归到我自己，那个最纯粹的自己。可我发现平常那个喜欢跟自己对话的我彻底蔫了，因为真的太累了。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>我这个人就是杂念太多，每天闷家里就是喜欢胡思乱想。总觉得出现问题要多跟自己对话，答案就能呼之欲出。可是每每质问自己的时候，我就陷到了特别负面的情绪里，会开始谴责和质疑自己。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' f7kmwtzb\'\'=\'\'\'\'>不但问题没有解决，还会把自己搞的一团乱。因为答案是找不到的，不去找反而就出现了。这一趟徒步让我看到，会胡思乱想是因为还不够累，真的够累就不会胡思乱想了。</p><p data-pid=\'\'\'\' \'\'=\'\'\'\' pdxrxa5m\'\'=\'\'\'\'>而且有想的时间不如去做，做的过程中答案就出现了。因为“想”是虚的，“做”才是实际的。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>这次爬山我也发现自己真的很有韧劲和毅力。当别人还在休息的时候，即便我也累，但我还是一鼓作气的上去了，因此才超越了很多徒步路上的排头兵。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' 3o-bylqz\'\'=\'\'\'\'>下山也是，每一步我都踩的很稳，也没有追求速度，而是跟着自己的节奏脚踏实地走好每一步。我也看到很多人因为恐高选择逆行的方式下山，突然我意识到，其实回避也是一种处理问题的方法。</p><p data-pid=\'\'\'\' \'\'=\'\'\'\' jqbb1zjb\'\'=\'\'\'\'>当身边人紧抓铁链颤颤巍巍下山时，我已经一步一脚印把他们甩在身后了。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>从爬山下山这两件事能看得出，我是一个愿意吃苦的人，困难面前是不认输的，总有一个要摆平它的决心，而且毅力和韧劲都够。只要按着我的节奏来，一切都没问题。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' b5lrv4_r\'\'=\'\'\'\'>还有就是面对这个急躁的社会，我是可以慢下来的，而且能掌控自己内心的节奏，不疾不徐地走好每一步。不追求速度的我，反而超越了走在前面的人。</p><figure data-size=\'\'\'\' \'\'=\'\'\'\' normal\'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>只不过这次也留下了遗憾，只登上了北峰顶、中风顶、东峰顶，西峰和南峰没有去。因为登顶后，去哪个峰都是人来人往，景色也都大同小异。和一开始的徒步相比，我觉得这样的自己，就只是在爬山而已，真没多大意思。</span><br></figure><p data-pid=\'\'\'\' \'\'=\'\'\'\' f6rntuaz\'\'=\'\'\'\'>反而在一个人徒步登顶的路上，脚步的丈量会更深，内心的感受会更多。虽然这次爬山爬的我快要吐了，但每一步都走的极其专注和认真，也是在这样一个完全投入的状态下，我才看见了山，看见了自己。</p>','2023-12-14'),
(43,'张','ac3b64a8169942e1a1d679be417cda18.png','杭州·西湖游记','<p data-first-child=\'\'\'\' data-pid=\'\'d2rhoojA\'\'>&nbsp; ‘东南形胜，三吴都会，钱塘自古繁华。’在白衣卿相的笔下，杭州是魂牵梦绕的人间天堂，是那醉人风流的万千景象。是啊，哪个中国人不曾有过这样的一个梦啊！在一个细雨朦胧的清晨，撑着一把油纸伞，走在那嘀嗒的青石板路上，望着远际一洗如碧的天空，烟云氤氲，笼罩着万里层云，我想所谓的仙人洞府也不过如此吧！而杭州就是这样的一个满足你一切幻想的城市。</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'GyAf3dxi\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>谁能想到两千多年前秦始皇设置的一个小县经过无数的风云变换后会在中国文化史上留下如此浓墨重彩。经过数百年的变迁，杭州在隋文帝平陈后正式登上历史舞台，兴起于盛唐，繁盛于五代，最后在两宋一跃成为中国有数的大都会。要知道当年吴越王治下的钱塘，‘十余万家，环以湖山，左右映带，而闽海商贾，风帆浪泊，出入于烟涛杳霭之间。’而到了南宋更是成为这古国的中心。这座整个东方人造梦的地方从此开始了它千古传奇的故事。</p><p data-pid=\'\'GyAf3dxi\'\'><br></p><p data-pid=\'\'nwtNx6gL\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>在那烟雨江南中，杭州无疑是其中的一颗耀眼的明珠，宛若无限星河里那绚烂的极光。生长与东海之滨，天然带着飘渺的仙气，特别在这醉人的江南里，显得犹外迷人和奇艳。</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'k6kG9itl\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>在我接触书本的幼小童年时，我还不知道一见钟情是什么意思，我只记得当时读到‘水光潋滟晴方好，山色空蒙雨亦奇’，读到‘乱花渐欲迷人眼，浅草才能没马蹄’，读到‘自别钱塘山水后，不多饮酒懒吟诗’时，我的心有种痒痒的感觉，那时我就下定决心，在我的人生里一定要有这座城的印记。这就是我和杭州的约定，一个没有人知道，似乎也很荒诞的约定，一个属于几乎懵懂无知的孩童自己一个人的秘密！</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'YQ8RuLMV\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>‘流光容易把人抛，红了樱桃，绿了芭蕉。’匆匆岁月，漫漫长途，回首望去，当年的天真无邪的孩子，如今已长成了一个青春少年，但那个已经深埋心底多年的秘密，是否还在？心颤了，这一动，放佛已沉静不知多久的湖面开始起了波澜，而这波澜一起，就是声涛汹涌、惊心动魄。是该让这个快要在记忆深处泛黄的约定重新散发它应有的光彩了。经过十几年的学海生涯的生活，我想总该出去走走了吧，看看外面的世界到底是不是乐天诗里那样，这座城市到底有什么魔力，醉晕了千年风流，醉倒了万古时光。 ‘江南好，风景旧曾谙；日出江花红胜火，春来江水绿如蓝。能不忆江南？’梦中的江南啊，我来了，你准备好了吗？少年！杭州！</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'WRdVxEdB\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>‘江南忆，最忆是杭州；山寺月中寻桂子，郡亭枕上看潮头。何日更重游！’在二十一世纪这个经济文化高度繁荣的社会里，旅游已经成为大多数人们生活里不可缺少的一部分了。那些名胜古迹，山河大川的景色里开始留下流连不绝的人迹踪影。在大家开始感慨祖国大好河山，期盼着与千年前的古人来次穿越时空的对望时，我想人们更在乎的是如何才能更好的探寻那悠悠景色里深藏的秘密。</p><p data-pid=\'\'QxI86OmL\'\'><br></p><p data-pid=\'\'QxI86OmL\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>这场跨越十一年的行旅就在今年的清明节，没有预划，却充满原由的开始了。肩上的行囊裹带着几件春装，拿着一张通往杭州的车票，就这样开始了这场梦想中的旅程。因为鄙人是学生的原因，考虑到自身经济情况和假期时间关系，在这满城风光的只能忍痛选择部分让我魂牵梦绕的景点，对此也深感遗憾，但是这不正是为下次的到来敲响了时钟嘛。那魂牵梦绕的杭州啊，我来了，你知道吗！</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'UMTUtstd\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>杭州之胜，首必西湖。我的旅途第一站就在苏仙笔下的西子湖畔。其实在后来我到达西湖湖畔时仔细了解西湖景区和周边景点以后，我十分庆幸我选择了一条十分适合我的路线，经济实惠又能不用浪费时间饱览西湖以及其周边景点。</p><p data-pid=\'\'r1iypf56\'\'><span style=\'\'font-size: 1rem;\'\'><br></span></p><p data-pid=\'\'r1iypf56\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>从湖滨公园大门进去，放眼之处皆是胜景！穿过一条长道，两岸湖滨在朝阳的照射下波光粼粼，极具美感，而它的终点，就是那天生散发着情思的断桥残雪。犹记得2007年，许嵩的那一首惊艳的《断桥残雪》横空出世，让我对西湖的憧憬更加格外迫切起来。</p><p data-pid=\'\'nnfli-yb\'\'><br></p><p data-pid=\'\'nnfli-yb\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>‘断桥是否下过雪？我望着湖面；水中寒月如雪，指尖轻点融解…’那风光足以杀人，夺走这观景客的灵魂。踏在断桥上，望着眼前那湾湖面，我在想，这要是冬天得多好啊！因为没有雪的断桥都如此迷人，那有了雪色的西湖会是怎么样的风采？我无法想象。前贤其实已经告诉我们了‘西湖之胜，晴湖不如雨湖，雨湖不如月湖，月湖不如雪湖。’今年冬天如果有机会我一定要再来一趟。</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'9eAV8GyY\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>告别了那撩人的断桥，慢慢走进下一个景点曲院风荷，东接岳湖，南邻郭庄，北接竹素园、植物园，当然还有那民族的骄傲岳武穆的庙祀。‘接天莲叶无穷碧，映日荷花别样红’，那正在孕养的菡萏，迎着阳光，在春风的扶持下别具一般风味。</p><p data-pid=\'\'6DV4TbVV\'\'><br></p><p data-pid=\'\'6DV4TbVV\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>芙蕖的香气还未散去，不知不觉中已经来到了岳庙，望着眼前的那高悬的牌匾，上边深深刻印着岳王庙三个大字，刚才还格外开朗的心情随之也沉重了起来。踏进不高的门槛，买了一张门票，因为是学生，全票25元的，半价只有12.5元。不得不说，票价真的不贵，对于岳飞，对于英雄，这点钱根本不足为道，虽然有点商业化的感觉，但算了吧，就当给岳王爷的香火钱。</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'PuXXSHk2\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>岳王庙里，不得不说，在欣赏风景的同时，来到这岳王庙，你才能明白今天的这一切是真的很珍贵的！如果没有那么多像岳武穆这样的人在国家危急时刻前仆后继、视死如归，这么美的江山，如此壮丽的山河，我们今天哪有机会来观赏啊。看看印第安人，想想曾经的非洲人民。</p><p data-pid=\'\'y7ZiGUHr\'\'><br></p><p data-pid=\'\'y7ZiGUHr\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>其实这才是杭州，这才是西湖让我牵挂更深的理由。在这一步一景的西湖里，还有那‘纵死犹闻侠骨香’的民族的脊梁，人民的英雄的精神时刻在捍卫着这大好的河山啊！江山如此多娇，多少豺狼在惦记环视着。但只要这岳王庙的香火不曾断绝，我们中国的壮丽河山依然如故，如那人间仙境、地上胜景。原来旅行的意义竟然如此深刻，这比任何的说教都要来得刻骨铭心吧。</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'GQ1vmeCc\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>依依告别那岳王庙，心绪一时难以平复。而眼前已换了风景。苏提春晓，南屏晚钟。这就是当年苏仙筑堤的地方吗？‘甚至再贬海南后，仍念念不忘西湖’。‘喂，东坡先生！你听得到嘛，我来了，我来到你念念不忘的地方了。我知道你听得见，你一定听得见的！这可是你曾深爱过的地方啊，杭州的百姓还有全天下的百姓都在想念着你呢。国泰民安，这盛世如你所愿！你看见了吗！谢谢你，谢谢你让西湖从此名绝天下，谢谢你让中国文化史因你更加灿烂。’</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'U62Wz8Xs\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>站在苏堤湖畔，入眼的云鸟不绝，那湖中的倒影，依稀照印着千古的风流往事，好像投影仪般，回放着九百年前那个羽冠纶巾的书生在湖中央慷慨高歌，带着无数杭州百姓筑起今天我脚下的这道长堤。天边的鸟儿掠过湖面，惊起一片涟漪。那书生的笑容渐渐归为湖影，晃了晃眼神，我知道刚才那个回首莞尔一笑的书生就是苏仙，是的，他的灵魂不成远去，一直依附在这道他当年倾尽心血筑成的湖堤上。守护着西湖，守护着这片他热爱且眷恋的人间！他将一生的美好留在了西湖，这本是他匡扶天下苍生的事业起点啊！可最终只能付与‘人生如梦，一尊还酹江月。’</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'JJIhGPe5\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>再美的风流过往也已成故事，再惊艳的天骄人杰也化为流星。但那故事吸引着无数的后世仁人前仆后继，但那流星坠落时划过天际的光芒震古烁今。岁月铭刻下了这故事，时光浸入进了这灵魂。那些消逝的豪情终将在我们的血脉里复苏，那些埋没的记忆终将在我们的灵魂里重现。谁说世间再无这般人？‘俱往矣，数风流人物，还看今朝’！</p><p data-pid=\'\'JJIhGPe5\'\'><br></p><p data-pid=\'\'kapj07BE\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>漫步一望无际的苏堤上，天色渐渐暗了下来，坐上了那前往三潭印月的游船，随着离堤岸越来越远，与天边一际。‘三潭塔分一月印，一波影中一圆晕’。已经开始西坠的金乌，离湖面越来越近，此时我方明白‘夕阳无限好’的真谛，如此景色，‘只是近黄昏’也不过耳后之想了。从岛北码头上岸，经过先贤祠等两座建筑，即步入九曲平桥，桥上有开网亭、迎翠亭、花架亭、御碑亭，康熙御碑亭，我心相印亭四座造型各异的亭子。布局浑然天成，让人惊叹。‘月光映潭，塔分为三’，不负小瀛洲之名。</p><p data-pid=\'\'kapj07BE\'\'><br></p><p data-pid=\'\'1CpXoBnx\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>坐在岛边石头上，放眼望去，苏堤上行人络绎不绝，一道残阳铺在水中，映红了大半湖面，摇摆的树影婆娑其中，此时此景，何用羡慕仙人啊，今日我就是那仙人，而这西湖就是那琅嬛福地、瑶池阆苑。在船回返苏堤的路上，心情是愉悦的，这般风景，如此清风，拂面而来的是满足和一丝贪婪，贪婪地想着时光在此定格该有多好。</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'87GjrSTn\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>‘青城山下白素贞，洞中千年修此身……’望着不远处的雷锋塔，脑海里回想起这段久别的歌声，不由自主地展开了一幅幅白娘子传奇的故事画面。雷峰夕照，晚霞连天。登上这座声名显赫天下的佛塔，向周边远眺而去，满目风光，入眼的尽是风情。这段传奇直到今天依然不绝于耳，频频在各种场合演绎着。</p><p data-pid=\'\'87GjrSTn\'\'><br></p><p data-pid=\'\'Yox9-R4l\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>前不久才去过金山，没想到现在此身已赴杭州，不得不说，真的是一种奇妙的感觉，放佛冥冥之中有种力量在作祟，不然就算我再怎么钟爱这座城，也不会如此急迫的出发赶来此地吧。是不是你，白姑娘，可惜我不是许仙。但我想你落得如此地步，你也是心甘情愿吧。‘只愿君心似我心，定不负相思意’。因恩而情，因情而不悔！这三日情缘又怎么的够！所以，就算日后永堕无间地狱，也要续下这一世绝恋！</p><figure data-size=\'\'normal\'\'><br></figure><p data-pid=\'\'GvhxUTBn\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>太阳终是落下了，我今天的旅程也快要结束了吧。这一日的时光啊，抵得上我过往十年的景色。而这一路的风情，终没相负我这十多年来的相思忆。在回去宾馆的路上，是坐着旅游专线最后出景区的，坐在窗边，望着渐渐被湖面吞食的金乌，脑海里回放着今天的历程，不由感慨如果能在西湖筑庐而居，那是多么大的幸福啊！</p><p data-pid=\'\'GvhxUTBn\'\'><br></p><p data-pid=\'\'QFzMZI2B\'\'><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span><span style=\'\'font-size: 1rem;\'\'>&nbsp;</span>江南的夜色总是撩人的，而杭州的夜色却是最醉人的。望着窗外的徐徐景色，阑珊灯火，这趟没有完整计划的说走就走的旅行是在太过完美，出乎意料。可能并不是我的运气好，而是杭州本来就是座幸运神奇的城市！你好，杭州。期待我们下次的再见！我相信，下一次的重逢，会是更美的夜色！</p>','2023-12-14');

/*Table structure for table `guestbook` */

DROP TABLE IF EXISTS `guestbook`;

CREATE TABLE `guestbook` (
  `guestbook_id` int NOT NULL AUTO_INCREMENT,
  `user_name` varchar(10) NOT NULL,
  `guestbook_title` varchar(100) CHARACTER SET utf16 COLLATE utf16_general_ci DEFAULT NULL,
  `guestbook_contents` text,
  `guestbook_addtime` date DEFAULT NULL,
  `guestbook_state` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`guestbook_id`)
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf16;

/*Data for the table `guestbook` */

insert  into `guestbook`(`guestbook_id`,`user_name`,`guestbook_title`,`guestbook_contents`,`guestbook_addtime`,`guestbook_state`) values 
(1,'Ryann','关于改善系统功能的建议','首先，思政教育有利于高校学生树立正确的价值观，为其健全心理的形成打下了基础。就目前而言，大学生的思想观念和心理健康同属于心理健康教育的内容，但在此内容中融入思政教育能够弥补心理健康教育的不足，使其教学的品质得到提升。另一方面，思政教育能够影响学生的价值观，使其在生活和学习中建立良好的心态，同时还有利于学生集体观念和个人思想的培养，促进心理机能的发展。由此可以看出，思政教育是心理健康教育的前提条件，只有拥有正确较之观念和道德思想的人，才能称之为心理健康的人。','2023-12-02',1),
(2,'张','关于性能的改进','最后，这两种教学内容的融合，能够丰富高校的教育形式，提高两者教育品质和效率。与思政教育相比，心理健康教育更适合应用个案分析、实验观察等方式进行教学，通过对具体事件的分析，让学生清晰地了解到自身心理的特质，以便在以后的生活和工作中规避此类不良现象的出现。通过对其做法的概述，让其了解到正确的做法是什么，以此促进高校学生解决问题能力的提升。另外，心理健康教育能够在对其个人进行全面的了解之后，将教育变成劝解，将制约变为疏导，这样可以在一定程度上改善学生与思政教师间的关系，推动思政教育的良好发展。','2023-12-03',1);

/*Table structure for table `notice` */

DROP TABLE IF EXISTS `notice`;

CREATE TABLE `notice` (
  `notice_id` int NOT NULL AUTO_INCREMENT,
  `scenic_name` varchar(100) CHARACTER SET utf16 COLLATE utf16_general_ci DEFAULT NULL,
  `notice_title` varchar(200) DEFAULT NULL,
  `notice_image` varchar(200) CHARACTER SET utf16 COLLATE utf16_general_ci DEFAULT NULL,
  `notice_contents` text,
  `notice_addtime` date DEFAULT NULL,
  PRIMARY KEY (`notice_id`)
) ENGINE=InnoDB AUTO_INCREMENT=135 DEFAULT CHARSET=utf16;

/*Data for the table `notice` */

insert  into `notice`(`notice_id`,`scenic_name`,`notice_title`,`notice_image`,`notice_contents`,`notice_addtime`) values 
(64,'云龙山','云龙山景点的天气通知','da2a6854b3f14e11ac7680066bfc464d.webp','<p><b>江苏徐州</b></p><p></p><p>云龙山今日天气的主要是“晴”。</p><p>7日白天到7日夜间天气晴，主要气温9~22℃，建议穿套装、夹衣、风衣、休闲装、夹克衫、西装、薄毛衣等保暖衣服。</p><p>7日夜间到8日早晨晴，气温降低至3~9℃，建议穿风衣、大衣、夹大衣、外套、毛衣、毛套装、西装、防寒服等保暖衣服。</p><p>从7日18时起，徐州云龙山未来24小时晴，同时未来两小时不会下雨，放心出门吧；</p><p>07日19时 - 明天16点，晴，温度在11 - 23℃;</p><p>云龙山的其他天气指数，风力3级 西南风， 相对湿度38%，紫外线强，空气质量62；</p>','2023-12-07'),
(106,'云龙山','行走在云龙湖景区的最美创建团队','563b4fcc9eca429ea1e6275e412004e4.png','<h5><div><ul><li><div><p>&nbsp; 今年以来，云龙湖风景名胜区行政执法大队坚持以人民为中心的执法理念，聚焦百姓城管精管善治、幸福景区美丽景区，按照“三个走在前”的创建目标，常态长效深化景区文明城市管理工作。</p><p><br></p><p><strong>一、“常态部署落实”走在前</strong></p><p><br></p><p>&nbsp; 景区划定文明城市创建责任包挂片区，领导班子牵头包挂、中队干部具体组织、一线队员实施落实，对照工作标准，提早部署落实，常规性落实市容秩序、绿化保洁、垃圾分类等创建任务，特色性推进野泳、遛狗、偷鱼、采荷等不文明行为治理，常态化落实景区创建交办、自查督办问题，确保部署问题第一时间交办回复、自查问题第一时间整改处置。</p><p><br></p><p><strong>二、“特色治理管控”走在前</strong></p><p><br></p><p>&nbsp; 三月到九月，云龙湖杏花、荷花分期绽放，相继再现一色杏花三十里、接天莲叶无穷碧的美景。为减少观景赏花过程中的不文明行为，大队积极探索管理模式，将普法宣传融入日常巡查和现场管理全过程，实行“定点+动态”及“正时+错时+延时”巡查模式，常态长效推进景区文明城市管理工作，面对面普法宣传，向更多市民游客传递出文明赏花、文明游览的旅游新风尚。</p><p><br></p><p>&nbsp; 炎炎夏季，大队持续推进水面秩序不文明行为专项整治，组织50余名城管队员，顶烈日、斗蚊虫、抢时间、建长效，重点整治湖中路等区域“野泳”“湖内打肥皂”等不文明行为。瑟瑟冬季，推进守护越冬候鸟文明志愿活动，对西湖生态区开展乱捕乱钓治理，有效守护候鸟安全过冬和维护正常生态秩序，助力全市文明城市创建工作。</p><p><br></p><p>&nbsp; 规范化执法，多方位保障，营造赛事文明好氛围。面对景区大型活动场地集中、赛事紧凑、持续保障等压力，大队定点定岗定人执勤，做好现场秩序维护，温馨提前告知市民游客限行安排，保障云龙湖全域范围内的文明环境，展示文明城市最美风采。</p><p><br></p><p><strong>三、“三级创建考核”走在前</strong></p><p><br></p><p>&nbsp; 云龙湖景区现已建立主管部门考核、数字化平台监督、队内监管等三级创建考核体系，通过创建交办、自查落实、督查考核，保证了创建问题快速发现与整改落实，目前，景区各类常见创建问题大幅下降，非机动车秩序、道路保洁、绿化养护、工地管理、街区垃圾分类等创建考核指标靠前，为景区常态长效做好文明城市管理工作提供了有力支撑。</p></div></li></ul></div></h5><p><br></p>','2023-12-13'),
(115,'九华山','九华山风景区最新公告','','<p>　4月26日，“九华山风景区”微信发布《关于九华山风景区 “五一”小长假期间实行预约管理的公告》，提醒游客提前一天通过“九华畅游”微信公众号等预约景区门票、车票。</p><p>　　↓↓↓</p><p>　　关于九华山风景区 “五一”小长假</p><p>　　期间实行预约管理的公告</p><p>　　广大游客朋友:</p><p>　　为积极应对“五一”假期客流高峰，营造安全有序的旅游环境和节日氛围，现将九华山风景区“五一”小长假期间预约管理有关事项公告如下:</p><p>　　一、请提前一天通过“九华畅游”微信公众号、“游九华”微信小程序预约景区门票、车票。游客当日预约数达最佳接待量5万人时，停止线上预约。符合优惠政策的游客可直接携带优惠证件到窗口办理。</p><p>　　二、“五一”小长假期间，风景区全面实行交通管控措施，请游客朋友们根据景区工作人员指引，将车辆停放至游客服务中心、大愿文化园游客服务中心、南庄游客分中心停车场或临时停车位，再换乘景区公交进入核心景区。</p><p>　　三、当游客接待量达到景区承载上限时，我们将启动远端分流举措，恳请广大游客理解和支持。</p><p>　　特此公告</p><p>　　九华山风景区管理委员会</p><p>　　2023年4月24日</p><p>　　转自：九华山风景区管理委员会</p><p>　　<font color=\'\'\'\' \'\'=\'\'\'\' #ff0000\'\'=\'\'\'\'>&nbsp;</font></p><div id=\'\'\'\' \'\'=\'\'\'\' contentliability\'\'=\'\'\'\'>[责任编辑：黄童欣]</div>','2023-12-14'),
(116,'太湖','关于紫金庵、天池山景区承载量调整及门票预约的通知','','<p>尊敬的游客朋友：&nbsp;</p><p>&nbsp; 根据《文化和旅游部办公厅关于进一步做好文化和旅游行业疫情防控工作的紧急通知》《苏州市疫情防控2021年第5号通告》要求，为进一步加强疫情防控工作，确保景区旅游接待安全有序，我公司下属景点紫金庵和天池山将按照控流量、防聚集、严防护的原则，严格执行限量接待、限流管控措施，具体如下：&nbsp;</p><p><strong>&nbsp; 一、景区开放时间</strong>&nbsp;</p><p>&nbsp; 紫金庵8:00—17:00； 天池山8:00-16:30&nbsp;</p><p><br></p><p><strong>&nbsp; 二、严格景区限控人数&nbsp;</strong></p><p>&nbsp; 紫金庵和天池山景区对人流量进行严格管控，按要求严格执行景区接待游客量不超过最大承载量和瞬时客流量的50%，并加强景区内重点区域的流量管控。&nbsp;</p><p><br></p><p><strong>&nbsp; 三、严格落实门票预约制&nbsp;</strong></p><p>&nbsp; 景区严格执行网上实名制预约或购票。&nbsp;</p><p><br></p><p><strong>&nbsp; 四、游客须知&nbsp;</strong></p><p>&nbsp; 游客需持本人有效身份证件，出示健康码、14天行程轨迹，主动配合我景区工作人员接受体温测量、登记信息，游览期间必须全程自觉佩戴口罩，依次有序游览，提倡不聚集、分线路游览方式，游览过程中请自觉与他人保持1米以上距离。&nbsp;</p><p>&nbsp; 我们将以严谨周密的防控措施和热情周到的优质服务，为您营造文明、安全、卫生、有序的游览环境。由此给广大游客带来的不便，敬请谅解，谢谢配合！&nbsp;</p><p>&nbsp;</p><p>苏州太湖旅游景区管理有限公司&nbsp;</p>','2023-12-14'),
(122,'西湖','本周末起，西湖景区停车收费有调整','d27382273fb34bf2a63c9f55454184e6.jpg','<p><b>&nbsp; 最近计划自驾前往西湖景区的车主们请注意，本周末起，西湖景区停车收费降价啦！</b></p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>西湖景区停车调价通知</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>根据杭州市物价相关规定，12月1日起，西湖景区秋季旅游旺季结束，景区价格浮动的政府定价停车场收费标准也相应进行调整：小型车周末白天的停车价格由20元/小时调整为10元/小时，其余不变。</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>具体收费标准如下：</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>1. 小型车、大型车白天（8时—20时）10元/辆•小时；</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>2. 小型车、大型车夜间（20时—次日8时）均为5元/辆•次。</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>西湖景区价格浮动的政府定价停车场</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>全年收费标准如何变化</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>可收藏下面这张表</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>眼下秋意正浓</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>西湖景区处处美景</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>抓住这个好时节</p><p><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>与西湖来场深秋之约吧</p><p><br></p>','2023-12-14'),
(125,'华山','华山景区淡季门票价格及运行时间调整公告','','<p>尊敬的游客朋友们:&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;华山景区自2023年12月1日零时至2024年2月29日执行淡季门票价格及运行时间。具体调整如下:&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;华山景区淡季门票执行:\n全价票100元/人·次。&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;半价票50元/人·次。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;特殊人群优惠政策按有关文件执行。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;华山景区运行时间执行:\n游客中心入园时间:8:00-16:00;&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;华山门(步行登山)入园时间: 24小时;&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;索道运营时间:8:00-18:00。&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;欢迎冬季您来华山赏雪景!&nbsp;</p><p><br></p>','2023-12-14'),
(132,'五台山','关于对五台山景区西、北线旅游大客车进行临时交通管控的通告','bc64af785a54444ba50b5e5f53c0cc76.png','<h5>&nbsp; 为进一步加强五台山风景名胜区道路交通管理，预防和减少道路交通事故，保障人民生命和财产安全，结合五台山风景名胜区冬季西、北线道路冰、雪、雾天气状况，旅游大客车通行存在重大交通安全隐患，五台山风景名胜区管理委员会研究决定，从2023年12月1日至2024年2月29日，对从西、北线进出五台山风景名胜区的旅游大客车实施交通管控，在上述时间段，旅游大客车从南线进出五台山风景名胜区。具体事项如下：</h5><p><br></p><p></p><section><strong>一、禁行路段</strong></section><section>五台山风景名胜区西线（台豆线0KM—14KM）、北线(砂石线33KM—44KM)的道路。</section><p><br></p><section><strong>二、禁行时间</strong></section><section>2023年12月1日至2024年2月29日。</section><p><br></p><section><strong>三、禁行规定</strong></section><section>全天24小时禁止旅游大客车在禁行路段内通行。</section><p><br></p><section><strong>四、除线路班车和执行任务的军用、警用、消防救援等车辆外，对违反本通告的大客车，依据《中华人民共和国道路交通安全法》相关规定进行处罚。</strong></section><section><strong><br></strong></section><section><strong>五、本通告自2023年12月1日起施行。</strong></section><section><strong><br></strong></section><section>特此通告。</section><section><br></section><p></p><p style=\'\'\'\' \'\'=\'\'\'\' text-align:=\'\'\'\' right;\'\'=\'\'\'\'>忻州市公安局五台山风景名胜区</p><p style=\'\'\'\' \'\'=\'\'\'\' text-align:=\'\'\'\' right;\'\'=\'\'\'\'>&nbsp;&nbsp;公安分局交通管理大队</p><p style=\'\'\'\' \'\'=\'\'\'\' text-align:=\'\'\'\' right;\'\'=\'\'\'\'>&nbsp;&nbsp;</p><p><br></p>','2023-12-14'),
(133,'琅琊山','关于琅琊山飞越丛林集装箱箱体广告设计施工安装项目招标公告','ae85f7a303594fde9a329dacef3f014e.png','<p align=\'\'\'\' \'\'=\'\'\'\'>&nbsp; 安徽省琅琊山旅游发展有限公司现对飞越丛林集装箱箱体画面、广告艺术字设计、制作、安装等项目进行招标，有关事项公告如下：<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><b><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>一、招标单位</b><o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>安徽省琅琊山旅游发展有限公司；项目地址：琅琊山飞越丛林探险乐园。<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><b><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>二、招标对象</b><o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>具备专业广告设计、制作、安装经验的企业。<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><b><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>三、投标要求</b><o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（一）投标单位应具备集装箱广告设计、施工和安装的相关经验；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（二）广告画面设计方案应符合品牌形象，具有创意和吸引力；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（三）施工过程应注重环保，遵守相关法律法规和安全规定；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（四）安装完成后，广告材质（材料）应具有稳定的性能和耐久性。<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><b><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>四、投标方式</b><o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>线下报名<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><b><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>五、投标事项</b><o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（一）投标材料包括：<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>1.团体、企业的营业执照复印件（盖章并标明与原件一致）；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>2.集装箱外墙广告、箱体广告字设计方案及概念图（后期实地安装的现场效果图）；</p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>3.施工方案、工程量及材料清单、相关技术参数；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>4.法人身份证复印件或经办人个人身份证复印件及授权委托书；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>5.联系人及联系方式等。<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（二）投标途径：<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>投标单位应于公告后5个工作日内，线下将材料密封后递交至本单位的招标工作小组。（递交地址：安徽省滁州市西涧中路4306号安徽省琅琊山旅游发展有限公司、联系电话15395501202）<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（三）投标截止日期：2023年11月30日<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（四）开标时间：2023年12月1日现场开标，具体时间待定<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（五）开标地点：安徽省滁州市西涧中路4306号安徽省琅琊山旅游发展有限公司<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（六）中标公示：<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>结果将于2023年12月5日在安徽省琅琊山旅游发展有限公司网站进行公示。<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><b><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>六、重要声明</b><o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（一）凡参加本次投标活动的单位，将被视为同意并接受本公告内容，无须书面或其它方式予以确认；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（二）参与本次招标的单位自行勘察现场，现场踏勘发生的费用和责任由投标人自行承担；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（三）本次设计施工安装费用需控制在2万元以内，广告画面设计方案采用后知识产权归安徽省琅琊山旅游发展有限公司所有；<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>（四）公示网站：安徽省琅琊山旅游发展有限公司网站网址：<span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>https://www.lysfjq.cn/</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>，琅琊山管委会网站网址：</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>https://lgw.chuzhou.gov.cn/index.html；</span></p><p align=\'\'\'\' \'\'=\'\'\'\'><o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'>（五）招标单位对本次活动保留最终解释权，相关评审过程由招标单位组织并保留最终解释权。<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><b><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>七、联系方式</b></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>联系电话：15395501202<o:p></o:p></p><p align=\'\'\'\' \'\'=\'\'\'\'><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span><span style=\'\'\'\' \'\'=\'\'\'\' font-size:=\'\'\'\' 1rem;\'\'=\'\'\'\'>&nbsp;</span>通讯地址：安徽省滁州市西涧中路4306号，安徽省琅琊山旅游发展有限公司。</p><p><br></p>','2023-12-14'),
(134,'泰山','关于寒潮天气的温馨提示','','<p setedaria=\'\'\'\' true\'\'=\'\'\'\'>&nbsp; 寒潮来临，气温骤降，泰山天气多变，请广大游客及有关单位、人员，密切关注天气变化情况（泰山景区微信公众号每日头条篇末有实时天气链接）和景区预警信息，主动做好防风防寒准备，理性出行、确保安全。游览期间如遇大风等，请立即暂停游览、迅速进入景区预设的应急避险场所，避免户外活动，不擅自进入非游览区域，并按照工作人员的指引就近紧急避险。另外，游客集中上山下山等时段，请自觉维护通行秩序，不在十八盘、天街等交通要道、险要地段逗留休息，确保旅游安全；泰山实行全年全域森林防火，请勿携带火种、危险品等进山，请勿在景区内吸烟、动用明火。</p><p setedaria=\'\'\'\' true\'\'=\'\'\'\'><br></p><p setedaria=\'\'\'\' true\'\'=\'\'\'\'>&nbsp; 泰山景区管委会&nbsp; &nbsp;&nbsp;</p><p setedaria=\'\'\'\' true\'\'=\'\'\'\'>&nbsp; 2023年11月6日&nbsp; &nbsp;&nbsp;</p><p setedaria=\'\'\'\' true\'\'=\'\'\'\'><br></p>','2023-12-14');

/*Table structure for table `scenic` */

DROP TABLE IF EXISTS `scenic`;

CREATE TABLE `scenic` (
  `scenic_id` int NOT NULL AUTO_INCREMENT,
  `scenic_name` varchar(200) DEFAULT NULL,
  `scenic_price` varchar(20) DEFAULT NULL,
  `scenic_contact` varchar(20) DEFAULT NULL,
  `scenic_address` varchar(100) DEFAULT NULL,
  `scenic_photo` varchar(200) DEFAULT NULL,
  `scenic_introduction` text CHARACTER SET utf16 COLLATE utf16_general_ci,
  `scenic_addtime` date DEFAULT NULL,
  PRIMARY KEY (`scenic_id`)
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf16;

